protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Preserve EF8 discriminator property name ("Discriminator" instead of EF9's "$type")
    // so existing documents and raw SQL queries like
    // SELECT * FROM c WHERE c.Discriminator = 'Blog' continue to work.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Preserve EF8 compound id format ("Blog|1") so existing documents
    // remain accessible via FindAsync and point-reads.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // REMOVED: .HasIndex(b => b.Name) — EF Core 9 Cosmos provider throws on
    // HasIndex. Manage indexing via the Azure Portal or Bicep/Terraform instead.
}

